func TestCatalogCapabilities_ReadOnlyResources(t *testing.T) {
	for _, resource := range []string{"products", "variants", "files"} {
		cap, ok := capabilityForResource(resource)
		if !ok {
			t.Fatalf("missing capability for %s", resource)
		}
		if !cap.List || !cap.Get {
			t.Errorf("%s should support list/get", resource)
		}
		if cap.Create || cap.Update || cap.Delete {
			t.Errorf("%s must be read-only, got create=%v update=%v delete=%v", resource, cap.Create, cap.Update, cap.Delete)
		}
		report := unsupportedResourceOperation(resource, "import")
		if report.Error != "resource_read_only" || report.Reason != "operation_not_supported_by_public_api" {
			t.Errorf("unexpected unsupported report for %s: %+v", resource, report)
		}
	}
}

func TestCheckoutCreatePayload_JSONAPI(t *testing.T) {
	payload := buildCheckoutCreatePayload(checkoutCreateOptions{
		StoreID:           "12345",
		VariantID:         "67890",
		RedirectURL:       "https://www.littlemight.com/ai-house-manager/thank-you/",
		ReceiptButtonText: "Download",
		Email:             "buyer@example.com",
		VariantQuantity:   2,
	})
	b, err := json.Marshal(payload)
	if err != nil {
		t.Fatal(err)
	}
	s := string(b)
	for _, want := range []string{
		`"type":"checkouts"`,
		`"store":{"data":{"id":"12345","type":"stores"}}`,
		`"variant":{"data":{"id":"67890","type":"variants"}}`,
		`"enabled_variants":["67890"]`,
		`"redirect_url":"https://www.littlemight.com/ai-house-manager/thank-you/"`,
		`"email":"buyer@example.com"`,
		`"variant_quantities":[{"quantity":2,"variant_id":"67890"}]`,
	} {
		if !strings.Contains(s, want) {
			t.Errorf("payload missing %s in %s", want, s)
		}
	}
}

func TestBuildCheckoutVerificationCommand_OmitsEmptyRedirectURL(t *testing.T) {
	cmd := buildCheckoutVerificationCommand("")
	if strings.Contains(cmd, "--redirect-url") {
		t.Fatalf("empty redirect URL should not emit --redirect-url flag: %s", cmd)
	}
	if !strings.Contains(cmd, "--dry-run --json") {
		t.Fatalf("verification command must remain a dry run: %s", cmd)
	}
}

func TestBuildCheckoutVerificationCommand_IncludesRedirectURL(t *testing.T) {
	cmd := buildCheckoutVerificationCommand("https://example.com/thanks")
	if !strings.Contains(cmd, "--redirect-url https://example.com/thanks --dry-run --json") {
		t.Fatalf("verification command should include redirect URL before dry-run flags: %s", cmd)
	}
}

